def rotl64(x: UInt64, k: Int) -> UInt64:
    var kk = k & 63
    if kk == 0:
        return x
    return (x << kk) | (x >> (64 - kk))

def rotr64(x: UInt64, k: Int) -> UInt64:
    var kk = k & 63
    if kk == 0:
        return x
    return (x >> kk) | (x << (64 - kk))

