def highest_bit_pos(n: UInt64) -> Int:
    if n == 0:
        return -1
    var p = -1
    var x = n
    while x != 0:
        p += 1
        x >>= 1
    return p

def fill_lowest_bits(n: Int) -> UInt64:
    if n == 0:
