    var m = (UInt64(1) << n) - 1
    return x & m

def reverse_byte(b: UInt64) -> UInt64:
    var r = UInt64(0)
    for i in range(8):
        r = (r << 1) | ((b >> i) & 1)
    return r

def round_up_pow2(n: UInt64) -> UInt64:
    if n <= 1:
