def interleave_bits(a: UInt64, b: UInt64) -> UInt64:
    var r = UInt64(0)
    for i in range(8):
        r |= ((a >> i) & 1) << (2 * i)
        r |= ((b >> i) & 1) << (2 * i + 1)
    return r

def bitwise_abs(n: Int) -> Int:
    var mask = n >> 63
    return (n + mask) ^ mask

